mapper.select:
select spu.id as id, spu.mch_id as mchId, mch.nickname as mchName, spu.shop_id as shopId, shop.shop_name as shopName, spu.spu_id as spuId, spu.activity_id as activityId, activity.name as activityName, spu.session_id as sessionId, session.name as sessionName, spu.name as name, spu.sales as sales, spu.main_image as mainImage, spu.min_origin_price as minOriginPrice, spu.min_seckill_price as minSeckillPrice, spu.max_origin_price as maxOriginPrice, spu.max_seckill_price as maxSeckillPrice, spu.detail_desc as detailDesc, spu.audit_status as auditStatus from s_seckill_spu spu left join s_merchant mch on spu.mch_id = mch.id and mch.deleted = 0 left join s_shop shop on spu.shop_id = shop.id and shop.deleted = 0 left join s_seckill_activity activity on spu.activity_id = activity.id and activity.deleted = 0 left join s_seckill_session session on spu.session_id = session.id and session.deleted = 0 where spu.deleted = 0
and spu.mch_id = #{mchId}
and spu.audit_status = #{query.auditStatus}
and spu.activity_id = #{query.activityId}
and spu.session_id = #{query.sessionId}
and mch.nickname like concat('%', #{query.mchName}, '%')
and shop.shop_name like concat('%', #{query.shopName}, '%')
and spu.name like concat('%', #{query.spuName}, '%')
